const fs2 = require('fs');
const input = $input.first().json;
const data = input.audioData || input;
const ELEVENLABS_API_KEY = input.ELEVENLABS_API_KEY || data.ELEVENLABS_API_KEY;

const videoId = data.videoId;
const tempDir = '/home/node/.n8n/temp/' + videoId;
fs2.mkdirSync(tempDir, { recursive: true });

let narracao = data.narracao || (data.script && data.script.narracao_completa) || '';

narracao = narracao
  .replace(/[\u{1F300}-\u{1FAFF}]/gu, '')
  .replace(/[\u2600-\u27BF]/gu, '')
  .replace(/[\u201C\u201D\u00AB\u00BB]/g, '"')
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/[\u2014\u2013]/g, ', ')
  .replace(/[*]+/g, '')
  .replace(/#[^ \t\r\n]*/g, '')
  .replace(/[\[]/g, '').replace(/]/g, '')
  .replace(/[ \t\r\n]{2,}/g, ' ')
  .trim();

return [{
  json: {
    videoId,
    narracao,
    tempDir,
    audioFile: tempDir + '/narration.mp3',
    ELEVENLABS_API_KEY
  }
}];

var driveData = $('Upload file').first().json;
var prepData = $('Prepare Audio Dir').first().json;

var fileId = driveData.id || driveData.fileId || '';
if (!fileId) throw new Error('Google Drive upload did not return a file ID');

var audioUrl = 'https://drive.google.com/uc?id=' + fileId + '&export=download&confirm=1';

return [{
  json: {
    videoId: prepData.videoId,
    audioFileId: fileId,
    audioFileName: driveData.name || prepData.audioFile,
    audioUrl: audioUrl,
    tempDir: prepData.tempDir,
    status: 'audio_ready'
  }
}];
